package sn.gestionimmobiliere.backend.billing.infrastructure;
import java.time.*;import java.util.*;import org.springframework.data.domain.*;import org.springframework.data.jpa.repository.*;import org.springframework.data.repository.query.Param;import jakarta.persistence.LockModeType;import sn.gestionimmobiliere.backend.billing.domain.*;
public interface RentChargeRepository extends JpaRepository<RentCharge,UUID>{Page<RentCharge> findAllByOrganizationId(UUID org,Pageable p);Optional<RentCharge> findByIdAndOrganizationId(UUID id,UUID org);@Lock(LockModeType.PESSIMISTIC_WRITE)@Query("select c from RentCharge c where c.id=:id and c.organizationId=:org")Optional<RentCharge> findForPayment(@Param("id")UUID id,@Param("org")UUID org);List<RentCharge> findAllByOrganizationIdAndStatusIn(UUID org,Collection<ChargeStatus> statuses);@Modifying@Query(value="INSERT INTO rent_charges (id,organization_id,lease_id,period_start,due_date,amount_due,amount_paid,status,created_at,updated_at) VALUES (:id,:org,:leaseId,:periodStart,:dueDate,:amount,0,:status,:now,:now) ON CONFLICT (organization_id,lease_id,period_start) DO NOTHING",nativeQuery=true)int insertIfAbsent(@Param("id")UUID id,@Param("org")UUID org,@Param("leaseId")UUID leaseId,@Param("periodStart")LocalDate periodStart,@Param("dueDate")LocalDate dueDate,@Param("amount")long amount,@Param("status")String status,@Param("now")Instant now);@Query("select coalesce(sum(c.amountDue),0) from RentCharge c where c.organizationId=:org")Long totalDue(@Param("org")UUID org);@Query("select coalesce(sum(c.amountPaid),0) from RentCharge c where c.organizationId=:org")Long totalPaid(@Param("org")UUID org);@Query("select coalesce(sum(c.amountDue-c.amountPaid),0) from RentCharge c where c.organizationId=:org and c.dueDate<:today and c.status not in (sn.gestionimmobiliere.backend.billing.domain.ChargeStatus.PAID,sn.gestionimmobiliere.backend.billing.domain.ChargeStatus.CANCELLED)")Long totalOverdueBalance(@Param("org")UUID org,@Param("today")LocalDate today);}
